const forwardDelta: Record<string, { dx: number; dy: number }> = {
  N: { dx: 0, dy: 1 },
  E: { dx: 1, dy: 0 },
  S: { dx: 0, dy: -1 },
  W: { dx: -1, dy: 0 },
};

const leftTurn: Record<string, string> = {
  N: "W",
  W: "S",
  S: "E",
  E: "N",
};

const rightTurn: Record<string, string> = {
  N: "E",
  E: "S",
  S: "W",
  W: "N",
};

export function moveRover(rover: { x: number; y: number; heading: string }, commands: string) {
  if (commands === "F") {
    const { dx, dy } = forwardDelta[rover.heading];
    return { ...rover, x: rover.x + dx, y: rover.y + dy };
  }
  if (commands === "L") {
    return { ...rover, heading: leftTurn[rover.heading] };
  }
  if (commands === "R") {
    return { ...rover, heading: rightTurn[rover.heading] };
  }
  return rover;
}

